import unittest
from src.login import provider_login

class LoginTest(unittest.TestCase):
    def test_google_and_github_create_local_sessions(self):
        for provider in ('google', 'github'):
            result = provider_login(provider, 'provider-secret')
            self.assertTrue(result.startswith('session:'))
            self.assertNotIn('provider-secret', result)
